1	/**
2	 * ANN-01 — pure rendering helpers for detail components.
3	 *
4	 * The plan canvas hosts three view-local 2D element kinds:
5	 *
6	 *   - `detail_line`    — open polyline (solid / dashed / dotted)
7	 *   - `detail_region`  — filled polygon with optional hatch pattern
8	 *   - `text_note`      — point-anchored label
9	 *
10	 * These elements are not visible in 3D. This module returns the
11	 * rendering primitives needed by the host renderer (three.js for the
12	 * plan canvas, SVG for the sheet preview). Each helper is pure and
13	 * easily unit-tested; the host wires them into a holder group.
14	 */
15	import type { Element, XY } from '@bim-ai/core';
16	
17	export type DetailLinePrimitive = {
18	  kind: 'detail_line';
19	  id: string;
20	  pointsMm: XY[];
21	  strokeMm: number;
22	  colour: string;
23	  style: 'solid' | 'dashed' | 'dotted';
24	};
25	
26	export type DetailRegionPrimitive = {
27	  kind: 'detail_region';
28	  id: string;
29	  boundaryMm: XY[];
30	  fillColour: string;
31	  fillPattern: 'solid' | 'hatch_45' | 'hatch_90' | 'crosshatch' | 'dots';
32	  strokeMm: number;
33	  strokeColour: string;
34	};
35	
36	export type TextNotePrimitive = {
37	  kind: 'text_note';
38	  id: string;
39	  positionMm: XY;
40	  text: string;
41	  fontSizeMm: number;
42	  anchor: 'tl' | 'tc' | 'tr' | 'cl' | 'c' | 'cr' | 'bl' | 'bc' | 'br';
43	  rotationDeg: number;
44	  colour: string;
45	};
46	
47	export type SpotElevationPrimitive = {
48	  kind: 'spot_elevation';
49	  id: string;
50	  positionMm: XY;
51	  elevationMm: number;
52	  prefix: string;
53	  suffix: string;
54	  colour: string;
55	};
56	
57	export type DetailComponentPrimitive =
58	  | DetailLinePrimitive
59	  | DetailRegionPrimitive
60	  | TextNotePrimitive
61	  | SpotElevationPrimitive;
62	
63	/**
64	 * Walks `elementsById` and returns rendering primitives for every
65	 * detail-component element hosted on `viewId`. Elements hosted on a
66	 * different view are excluded so each plan view shows only its own
67	 * annotations.
68	 */
69	export function extractDetailComponentPrimitives(
70	  elementsById: Record<string, Element>,
71	  viewId: string | undefined,
72	): DetailComponentPrimitive[] {
73	  if (!viewId) return [];
74	  const out: DetailComponentPrimitive[] = [];
75	  for (const el of Object.values(elementsById)) {
76	    if (el.kind === 'detail_line' && el.hostViewId === viewId) {
77	      out.push({
78	        kind: 'detail_line',
79	        id: el.id,
80	        pointsMm: el.pointsMm,
81	        strokeMm: el.strokeMm ?? 1.0,
82	        colour: el.colour ?? '#202020',
83	        style: el.style ?? 'solid',
84	      });
85	    } else if (el.kind === 'detail_region' && el.hostViewId === viewId) {
86	      out.push({
87	        kind: 'detail_region',
88	        id: el.id,
89	        boundaryMm: el.boundaryMm ?? [],
90	        fillColour: el.fillColour ?? '#cccccc',
91	        fillPattern: el.fillPattern ?? 'solid',
92	        strokeMm: el.strokeMm ?? 0.5,
93	        strokeColour: el.strokeColour ?? '#202020',
94	      });
95	    } else if (el.kind === 'text_note' && el.hostViewId === viewId) {
96	      out.push({
97	        kind: 'text_note',
98	        id: el.id,
99	        positionMm: el.positionMm,
100	        text: el.text,
101	        fontSizeMm: el.fontSizeMm,
102	        anchor: el.anchor ?? 'tl',
103	        rotationDeg: el.rotationDeg ?? 0,
104	        colour: el.colour ?? '#202020',
105	      });
106	    } else if (el.kind === 'spot_elevation' && el.hostViewId === viewId) {
107	      out.push({
108	        kind: 'spot_elevation',
109	        id: el.id,
110	        positionMm: el.positionMm,
111	        elevationMm: el.elevationMm,
112	        prefix: el.prefix ?? '',
113	        suffix: el.suffix ?? '',
114	        colour: el.colour ?? '#202020',
115	      });
116	    }
117	  }
118	  return out;
119	}
120	
121	/**
122	 * Maps a `text_note.anchor` to the SVG `text-anchor` and `dominant-
123	 * baseline` attributes used by the sheet renderer. Pure — exposed so
124	 * downstream renderers can stay declarative.
125	 */
126	export function svgTextAnchorAttrs(anchor: TextNotePrimitive['anchor']): {
127	  textAnchor: 'start' | 'middle' | 'end';
128	  dominantBaseline: 'hanging' | 'middle' | 'baseline';
129	} {
130	  const horizontal = anchor[1];
131	  const vertical = anchor[0];
132	  const textAnchor = horizontal === 'l' ? 'start' : horizontal === 'r' ? 'end' : 'middle';
133	  const dominantBaseline = vertical === 't' ? 'hanging' : vertical === 'b' ? 'baseline' : 'middle';
134	  return { textAnchor, dominantBaseline };
135	}
136	
137	/**
138	 * Returns the SVG `pattern` definition fragment for a detail-region
139	 * fill pattern at the supplied colour. Returns `null` for `'solid'`
140	 * because solid fills don't need a pattern element. The returned
141	 * fragment is pure data so callers can inline it into their SVG tree.
142	 */
143	export function svgFillPatternDef(
144	  pattern: DetailRegionPrimitive['fillPattern'],
145	  colour: string,
146	): { id: string; svg: string } | null {
147	  if (pattern === 'solid') return null;
148	  const id = `detail-pattern-${pattern}-${colour.replace('#', '')}`;
149	  if (pattern === 'hatch_45') {
150	    return {
151	      id,
152	      svg: `<pattern id="${id}" patternUnits="userSpaceOnUse" width="6" height="6" patternTransform="rotate(45)"><line x1="0" y1="0" x2="0" y2="6" stroke="${colour}" stroke-width="1"/></pattern>`,
153	    };
154	  }
155	  if (pattern === 'hatch_90') {
156	    return {
157	      id,
158	      svg: `<pattern id="${id}" patternUnits="userSpaceOnUse" width="6" height="6"><line x1="0" y1="0" x2="0" y2="6" stroke="${colour}" stroke-width="1"/></pattern>`,
159	    };
160	  }
161	  if (pattern === 'crosshatch') {
162	    return {
163	      id,
164	      svg: `<pattern id="${id}" patternUnits="userSpaceOnUse" width="8" height="8"><path d="M0 0L8 8M8 0L0 8" stroke="${colour}" stroke-width="0.8"/></pattern>`,
165	    };
166	  }
167	  // dots
168	  return {
169	    id,
170	    svg: `<pattern id="${id}" patternUnits="userSpaceOnUse" width="6" height="6"><circle cx="3" cy="3" r="0.9" fill="${colour}"/></pattern>`,
171	  };
172	}
173	
174	/**
175	 * Computes a 2D pixel offset from a (positionMm, anchor) pair given a
176	 * bounding rectangle (textWidthMm × textHeightMm). The returned offset
177	 * is what `text-anchor` / `dominant-baseline` cannot express in three.js
178	 * (which has no built-in text alignment).
179	 */
180	export function textNoteAnchorOffsetMm(
181	  anchor: TextNotePrimitive['anchor'],
182	  textWidthMm: number,
183	  textHeightMm: number,
184	): { dxMm: number; dyMm: number } {
185	  const horizontal = anchor[1];
186	  const vertical = anchor[0];
187	  const dxMm = horizontal === 'l' ? 0 : horizontal === 'r' ? -textWidthMm : -textWidthMm / 2;
188	  const dyMm = vertical === 't' ? -textHeightMm : vertical === 'b' ? 0 : -textHeightMm / 2;
189	  return { dxMm, dyMm };
190	}
